                        className={`flex items-center gap-2 px-4 py-2 rounded-lg transition-colors ${
                          theme === 'dark' ? 'bg-gray-700 hover:bg-gray-600' : 'bg-gray-200 hover:bg-gray-300'
                        }`}
                      >
                        <Star size={18} /> {showHint ? 'Hide Hint' : 'Show Hint'}
                      </button>
                      <button onClick={openQuizPage} className="flex items-center gap-2 px-4 py-2 bg-purple-600 hover:bg-purple-500 rounded-lg transition-colors">
                        <Trophy size={18} /> Take Quiz
                      </button>
                    </div>
                  </div>

                  <div className="flex gap-3">
                    <button
                      onClick={prevLesson}
                      disabled={currentLesson === 0}
                      className={`flex-1 py-3 rounded-lg font-medium transition-colors ${
                        theme === 'dark' ? 'bg-gray-700 hover:bg-gray-600 disabled:opacity-50' : 'bg-gray-200 hover:bg-gray-300 disabled:opacity-50'
                      }`}
                    >
                      Previous
                    </button>
                    <button
                      onClick={nextLesson}
                      disabled={currentLesson === LESSONS[selectedLang].length - 1}
                      className="flex-1 py-3 bg-blue-600 hover:bg-blue-500 disabled:opacity-50 rounded-lg font-medium flex items-center justify-center gap-2"
                    >
                      Next <ChevronRight size={18} />
                    </button>
                  </div>

                  <div className={`${theme === 'dark' ? 'bg-gray-800' : 'bg-white shadow-md'} rounded-xl p-6`}>
                    <div className="flex items-center gap-2 mb-4">
                      <MessageCircle size={20} className="text-purple-400" />
                      <h3 className="font-bold">Ask a Doubt</h3>
                      <span className="text-xs text-gray-400 ml-auto">Global Chat</span>
                    </div>
                    <div className="space-y-3 max-h-40 overflow-y-auto mb-4">
                      {[...globalDoubts, ...doubts].map((d, i) => (
                        <div key={i} className={`${theme === 'dark' ? 'bg-gray-700' : 'bg-gray-100'} rounded-lg p-3`}>
                          <div className="flex items-center gap-2 mb-1">
                            <span className="font-bold text-sm">{d.user}</span>
                            <span className={`text-xs ${theme === 'dark' ? 'text-gray-400' : 'text-gray-500'}`}>{d.time}</span>
                            {d.userId === userId && <span className="text-xs bg-blue-500 text-white px-2 py-1 rounded-full ml-auto">YOU</span>}
                          </div>
                          <p className={`text-sm ${theme === 'dark' ? 'text-gray-300' : 'text-gray-700'}`}>{d.msg}</p>
                        </div>
                      ))}
                    </div>
                    <div className="flex gap-2">
                      <input
                        value={doubtMsg}
                        onChange={(e) => setDoubtMsg(e.target.value)}
                        placeholder={username ? "Type your question..." : "Set your nickname first..."}
                        disabled={!username}
                        className={`flex-1 border rounded-lg px-4 py-2 focus:outline-none focus:border-blue-500 ${
                          theme === 'dark' ? 'bg-gray-700 border-gray-600 text-white placeholder-gray-400' : 'bg-gray-100 border-gray-300 text-gray-900 placeholder-gray-500'
                        }`}
                      />
                      <button 
                        onClick={sendDoubt} 
                        disabled={!username || !doubtMsg.trim()}
                        className="px-4 py-2 bg-purple-600 hover:bg-purple-500 disabled:opacity-50 rounded-lg"
                      >
                        Send
                      </button>
                    </div>
                  </div>
                </div>

                {/* Right Column */}
                <div className="space-y-4">
                  <div className={`${theme === 'dark' ? 'bg-gray-800' : 'bg-white shadow-md'} rounded-xl overflow-hidden`}>
                    <div className={`${theme === 'dark' ? 'bg-gray-900 border-gray-700' : 'bg-gray-100 border-gray-300'} px-4 py-3 flex items-center justify-between border-b`}>
                      <div className="flex items-center gap-2">
                        <Code size={18} className={theme === 'dark' ? 'text-gray-400' : 'text-gray-600'} />
                        <span className={`text-sm font-medium ${theme === 'dark' ? 'text-gray-300' : 'text-gray-700'}`}>
                          main.{selectedLang === 'javascript' ? 'js' : selectedLang === 'python' ? 'py' : selectedLang}
                        </span>
                      </div>
                      <button onClick={runCode} className="flex items-center gap-2 px-4 py-2 bg-green-600 hover:bg-green-500 rounded-lg text-sm font-medium">
                        <Play size={16} /> Run Code
                      </button>
                    </div>
                    <Editor
                      height="300px"
                      language={selectedLang === 'html' ? 'html' : selectedLang === 'css' ? 'css' : selectedLang}
