                  </div>

                  <div className={`${theme === 'dark' ? 'bg-gray-800' : 'bg-white shadow-md'} rounded-xl p-4`}>
                    <div className="flex items-center gap-2 mb-3">
                      <div className={`w-2 h-2 rounded-full ${output ? 'bg-green-500' : theme === 'dark' ? 'bg-gray-500' : 'bg-gray-400'}`} />
                      <span className={`text-sm font-medium ${theme === 'dark' ? 'text-gray-300' : 'text-gray-700'}`}>Output</span>
