                      onClick={submitQuiz}
                      disabled={Object.keys(quizAnswers).length !== lesson.quiz.length}
                      className="w-full py-3 bg-green-600 hover:bg-green-500 disabled:opacity-50 disabled:cursor-not-allowed rounded-xl font-bold text-lg"
                    >
                      Submit Quiz
                    </button>
                  </>
                ) : (
                  <div className="text-center">
                    <div className={`mb-4 ${quizScore === lesson.quiz.length ? 'text-green-500' : 'text-yellow-500'}`}>
                      {quizScore === lesson.quiz.length ? <Trophy size={80} className="mx-auto" /> : <Star size={80} className="mx-auto" />}
                    </div>
                    <h3 className="text-3xl font-bold mb-2">
                      {quizScore === lesson.quiz.length ? 'Perfect Score!' : 'Quiz Completed!'}
                    </h3>
                    <p className="text-xl mb-4">
                      You scored <span className="font-bold text-blue-400">{quizScore}</span> out of <span className="font-bold">{lesson.quiz.length}</span>
                    </p>
                    {quizScore === lesson.quiz.length && (
                      <p className="text-green-400 font-bold mb-4">+20 XP Bonus!</p>
                    )}
                    <div className="space-y-3 mt-6">
                      {lesson.quiz.map((q, idx) => (
                        <div key={idx} className={`p-3 rounded-lg text-left ${quizAnswers[idx] === q.correct ? 'bg-green-500/20' : 'bg-red-500/20'}`}>
                          <p className="font-medium">{idx + 1}. {q.question}</p>
                          <p className="text-sm mt-1">
                            Your answer: {q.options[quizAnswers[idx]]} {quizAnswers[idx] === q.correct ? '✓' : '✗'}
                          </p>
                          {quizAnswers[idx] !== q.correct && (
                            <p className="text-sm text-green-400 mt-1">Correct: {q.options[q.correct]}</p>
                          )}
                        </div>
                      ))}
                    </div>
                    <button
                      onClick={() => setCurrentPage('learn')}
                      className="mt-6 px-8 py-3 bg-blue-600 hover:bg-blue-500 rounded-xl font-bold"
                    >
                      Back to Learn
                    </button>
                  </div>
                )}
              </div>
            </div>
          )}

          {/* Journey Page */}
          {currentPage === 'journey' && (
            <div className="p-8">
              <div className="max-w-6xl mx-auto">
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
                  {LANGUAGES.map((lang) => {
                    const langCompleted = completed.filter(c => c.startsWith(lang.id)).length;
                    const totalLessons = LESSONS[lang.id].length;
                    const langProgress = (langCompleted / totalLessons) * 100;

                    return (
                      <div key={lang.id} className={`${theme === 'dark' ? 'bg-gray-800' : 'bg-white shadow-md'} rounded-xl p-6`}>
                        <div className="flex items-center gap-3 mb-4">
                          <span className="text-3xl">{lang.icon}</span>
                          <h3 className="font-bold text-lg">{lang.name}</h3>
                        </div>
                        <div className="mb-4">
                          <div className="flex justify-between text-sm mb-2">
                            <span>{langCompleted}/{totalLessons} completed</span>
                            <span>{langProgress.toFixed(0)}%</span>
                          </div>
                          <div className={`h-2 ${theme === 'dark' ? 'bg-gray-700' : 'bg-gray-200'} rounded-full overflow-hidden`}>
                            <div className="h-full bg-gradient-to-r from-blue-500 to-purple-500" style={{ width: `${langProgress}%` }} />
                          </div>
                        </div>
                        {langCompleted === totalLessons && (
                          <div className="flex items-center gap-2 text-green-400">
                            <CheckCircle size={20} />
                            <span className="font-medium">Completed!</span>
                          </div>
                        )}
                      </div>
                    );
                  })}
                </div>

                <div className={`${theme === 'dark' ? 'bg-gray-800' : 'bg-white shadow-md'} rounded-xl p-6`}>
                  <h3 className="text-xl font-bold mb-4">Your Learning Journey</h3>
                  <div className="space-y-4">
                    {LANGUAGES.map((lang) => (
                      <div key={lang.id} className={`p-4 rounded-lg ${theme === 'dark' ? 'bg-gray-700' : 'bg-gray-100'}`}>
                        <div className="flex items-center justify-between mb-3">
                          <div className="flex items-center gap-3">
                            <span className="text-2xl">{lang.icon}</span>
                            <h4 className="font-bold">{lang.name} Path</h4>
                          </div>
                          <span className={`px-3 py-1 rounded-full text-sm font-medium ${
                            completed.filter(c => c.startsWith(lang.id)).length === LESSONS[lang.id].length
                              ? 'bg-green-500/20 text-green-400'
                              : 'bg-yellow-500/20 text-yellow-400'
                          }`}>
                            {completed.filter(c => c.startsWith(lang.id)).length}/{LESSONS[lang.id].length}
                          </span>
                        </div>
                        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-2">
                          {LESSONS[lang.id].map((l, idx) => (
                            <div
                              key={idx}
                              className={`p-2 rounded-lg text-center text-sm ${
                                completed.includes(`${lang.id}-${idx}`)
                                  ? 'bg-green-500/20 text-green-400'
                                  : 'bg-gray-500/20 text-gray-400'
                              }`}
                            >
                              {completed.includes(`${lang.id}-${idx}`) ? <CheckCircle size={16} className="inline" /> : <Star size={16} className="inline" />}
                              {' '}{l.title}
                            </div>
                          ))}
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* Leaderboard Page */}
          {currentPage === 'leaderboard' && (
            <div className="p-8">
              <div className="max-w-4xl mx-auto">
                <div className={`${theme === 'dark' ? 'bg-gray-800' : 'bg-white shadow-md'} rounded-xl p-6 mb-6`}>
                  <div className="flex items-center justify-between mb-4">
                    <h3 className="text-xl font-bold">Global Leaderboard</h3>
                    <button
                      onClick={refreshLeaderboard}
                      className={`flex items-center gap-2 px-4 py-2 rounded-lg transition-colors ${
                        theme === 'dark' ? 'bg-gray-700 hover:bg-gray-600' : 'bg-gray-200 hover:bg-gray-300'
                      }`}
                    >
                      🔄 Refresh
                    </button>
                  </div>
                  <div className="space-y-3">
                    {leaderboard.length > 0 ? (
                      leaderboard.map((user, idx) => (
                        <div key={user.userId} className={`flex items-center gap-4 p-4 rounded-lg ${
                          user.userId === userId
                            ? 'bg-blue-500/20 border border-blue-500/50'
                            : theme === 'dark' ? 'bg-gray-700' : 'bg-gray-100'
                        }`}>
                          <div className={`w-12 h-12 rounded-full flex items-center justify-center font-bold text-lg ${
                            idx < 3 ? 'bg-gradient-to-r from-yellow-500 to-orange-500' : 'bg-gray-500'
                          }`}>
                            {idx < 3 ? ['🏆', '🥈', '🥉'][idx] : '⭐'}
                          </div>
                          <div className="flex-1">
                            <div className="flex items-center gap-2">
                              <span className="font-bold">{user.username}</span>
                              {user.userId === userId && <span className="text-xs bg-blue-500 text-white px-2 py-1 rounded-full">YOU</span>}
                            </div>
                            <div className="flex items-center gap-4 text-sm text-gray-400">
                              <span>Rank #{idx + 1}</span>
                              <span>{user.xp} XP</span>
                              <span>{user.streak} day streak</span>
                            </div>
                          </div>
                        </div>
                      ))
                    ) : (
                      <div className="text-center py-8 text-gray-400">
                        <p>No leaderboard data yet</p>
                        <p className="text-sm">Be the first to complete lessons!</p>
                      </div>
                    )}
                  </div>
                </div>

                <div className={`${theme === 'dark' ? 'bg-gray-800' : 'bg-white shadow-md'} rounded-xl p-6`}>
                  <h3 className="text-xl font-bold mb-4">Weekly Challenge</h3>
                  <div className={`p-4 rounded-lg ${theme === 'dark' ? 'bg-gray-700' : 'bg-gray-100'}`}>
                    <div className="flex items-center justify-between mb-3">
                      <h4 className="font-bold">Python Basics Challenge</h4>
                      <span className="text-sm text-gray-400">2 days left</span>
                    </div>
                    <p className="text-sm mb-3">Complete all Python lessons to earn 100 bonus XP!</p>
                    <div className="flex items-center gap-2">
                      <div className="flex-1 h-2 bg-gray-600 rounded-full overflow-hidden">
                        <div className="h-full bg-gradient-to-r from-green-500 to-blue-500" style={{ width: '66%' }} />
                      </div>
                      <span className="text-sm font-medium">2/3 completed</span>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* Profile Page */}
          {currentPage === 'profile' && (
            <div className="p-8">
              <div className="max-w-4xl mx-auto">
                <div className={`${theme === 'dark' ? 'bg-gray-800' : 'bg-white shadow-md'} rounded-xl p-8 mb-6`}>
                  <div className="flex items-center gap-6 mb-6">
                    <div className="w-24 h-24 bg-gradient-to-r from-purple-500 to-pink-500 rounded-full flex items-center justify-center text-white font-bold text-3xl">
                      {username ? username[0].toUpperCase() : 'U'}
                    </div>
                    <div>
                      <h2 className="text-2xl font-bold mb-2">{username || 'Anonymous'}</h2>
                      <p className="text-gray-400">Member since March 2024</p>
                      <p className="text-xs text-gray-500 mt-1">ID: {userId}</p>
                    </div>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-6">
                    <div className={`p-4 rounded-lg text-center ${theme === 'dark' ? 'bg-gray-700' : 'bg-gray-100'}`}>
                      <div className="text-3xl mb-2">🏆</div>
                      <div className="text-2xl font-bold">{xp}</div>
                      <div className="text-sm text-gray-400">Total XP</div>
                    </div>
                    <div className={`p-4 rounded-lg text-center ${theme === 'dark' ? 'bg-gray-700' : 'bg-gray-100'}`}>
                      <div className="text-3xl mb-2">🔥</div>
                      <div className="text-2xl font-bold">{streak}</div>
                      <div className="text-sm text-gray-400">Day Streak</div>
                    </div>
                    <div className={`p-4 rounded-lg text-center ${theme === 'dark' ? 'bg-gray-700' : 'bg-gray-100'}`}>
                      <div className="text-3xl mb-2">📚</div>
                      <div className="text-2xl font-bold">{completed.length}</div>
                      <div className="text-sm text-gray-400">Lessons Completed</div>
                    </div>
                  </div>

                  <div className="space-y-4">
                    <h3 className="text-lg font-bold">Achievements</h3>
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                      {[
                        { icon: '🎯', name: 'First Steps', earned: true },
                        { icon: '🐍', name: 'Python Beginner', earned: true },
                        { icon: '⚡', name: 'JavaScript Starter', earned: false },
                        { icon: '🌐', name: 'HTML Expert', earned: false },
                      ].map((achievement, idx) => (
                        <div key={idx} className={`p-3 rounded-lg text-center ${
                          achievement.earned
                            ? 'bg-yellow-500/20 border border-yellow-500/50'
                            : theme === 'dark' ? 'bg-gray-700 opacity-50' : 'bg-gray-100 opacity-50'
                        }`}>
                          <div className="text-2xl mb-1">{achievement.icon}</div>
                          <div className="text-xs font-medium">{achievement.name}</div>
                        </div>
                      ))}
                    </div>
                  </div>
                </div>

                <div className={`${theme === 'dark' ? 'bg-gray-800' : 'bg-white shadow-md'} rounded-xl p-6`}>
                  <h3 className="text-xl font-bold mb-4">Learning Statistics</h3>
                  <div className="space-y-3">
                    {LANGUAGES.map((lang) => {
                      const langCompleted = completed.filter(c => c.startsWith(lang.id)).length;
                      return (
                        <div key={lang.id} className={`flex items-center justify-between p-3 rounded-lg ${theme === 'dark' ? 'bg-gray-700' : 'bg-gray-100'}`}>
                          <div className="flex items-center gap-3">
                            <span className="text-xl">{lang.icon}</span>
                            <span className="font-medium">{lang.name}</span>
                          </div>
                          <span className="text-sm text-gray-400">{langCompleted}/{LESSONS[lang.id].length} lessons</span>
                        </div>
                      );
                    })}
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </>
  );
}

export default App;
